(1001, 10, '硫化氢中毒风险', '硫化氢中毒风险隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1002, 10, '一氧化碳中毒风险', '一氧化碳中毒风险隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1003, 10, '密闭空间窒息风险', '密闭空间窒息风险隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1004, 10, '缺氧环境风险', '缺氧环境风险隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1005, 10, '有害气体急性中毒', '有害气体急性中毒隐患排查', '重大', '《中华人民共和国职业病防治法》', '第四条', '劳动者依法享有职业卫生保护的权利。用人单位应当为劳动者创造符合国家职业卫生标准和卫生要求的工作环境和条件，并采取措施保障劳动者获得职业卫生保护。'),
(1006, 10, '有机溶剂中毒', '有机溶剂中毒隐患排查', '较大', '《中华人民共和国职业病防治法》', '第二十二条', '用人单位必须采用有效的职业病防护设施，并为劳动者提供个人使用的职业病防护用品。用人单位为劳动者个人提供的职业病防护用品必须符合防治职业病的要求；不符合要求的，不得使用。'),
(1007, 10, '正己烷中毒', '正己烷中毒隐患排查', '一般', '《中华人民共和国职业病防治法》', '第三十三条', '用人单位与劳动者订立劳动合同（含聘用合同，下同）时，应当将工作过程中可能产生的职业病危害及其后果、职业病防护措施和待遇等如实告知劳动者，并在劳动合同中写明，不得隐瞒或者欺骗。劳动者在已订立劳动合同期间因工作岗位或者工作内容变更，从事与所订立劳动合同中未告知的存在职业病危害的作业时，用人单位应当依照前款规定，向劳动者履行如实告知的义务，并协商变更原劳动合同相关条款。'),
(1008, 10, '三氯乙烯中毒', '三氯乙烯中毒隐患排查', '重大', '《中华人民共和国职业病防治法》', '第三十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训，普及职业卫生知识，督促劳动者遵守职业病防治法律、法规、规章和操作规程，指导劳动者正确使用职业病防护设备和个人使用的职业病防护用品。'),
(1009, 10, '二甲基甲酰胺中毒', '二甲基甲酰胺中毒隐患排查', '较大', '《工作场所职业卫生管理规定》', '第十二条', '用人单位应当对工作场所进行职业病危害因素检测、评价。检测、评价结果存入用人单位职业卫生档案，定期向所在地卫生健康主管部门报告并向劳动者公布。'),
(1010, 10, '丙酮中毒', '丙酮中毒隐患排查', '一般', '《工作场所职业卫生管理规定》', '第十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训。'),
(1011, 10, '重金属中毒', '重金属中毒隐患排查', '重大', '《工作场所有害因素职业接触限值第1部分：化学有害因素》GBZ 2.1-2019', '第4.1条', '工作场所化学有害因素职业接触限值包括时间加权平均容许浓度、短时间接触容许浓度和最高容许浓度三类。'),
(1012, 10, '铅中毒', '铅中毒隐患排查', '较大', '《工作场所有害因素职业接触限值第2部分：物理因素》GBZ 2.2-2007', '第4.1条', '工作场所物理因素职业接触限值包括噪声、高温、低温、微波辐射、激光辐射、紫外辐射、红外辐射等各类物理因素的限值要求。'),
(1013, 10, '汞中毒', '汞中毒隐患排查', '一般', '《用人单位职业病危害告知与警示标识管理规范》', '第三条', '用人单位应当将工作场所职业病危害因素和职业病危害后果等以书面形式告知劳动者。'),
(1014, 10, '镉中毒', '镉中毒隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1015, 10, '锰中毒', '锰中毒隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1016, 10, '铍中毒', '铍中毒隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1017, 10, '职业性皮肤病', '职业性皮肤病隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1018, 10, '接触性皮炎', '接触性皮炎隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1019, 10, '电光性皮炎', '电光性皮炎隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1020, 10, '化学性皮肤灼伤', '化学性皮肤灼伤隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1021, 10, '职业性痤疮', '职业性痤疮隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1022, 10, '职业性眼病', '职业性眼病隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1023, 10, '电光性眼炎', '电光性眼炎隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1024, 10, '化学性眼灼伤', '化学性眼灼伤隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1025, 10, '职业性白内障', '职业性白内障隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1026, 10, '辐射性白内障', '辐射性白内障隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1027, 10, '耳鼻喉口腔疾病', '耳鼻喉口腔疾病隐患排查', '较大', '《中华人民共和国职业病防治法》', '第四条', '劳动者依法享有职业卫生保护的权利。用人单位应当为劳动者创造符合国家职业卫生标准和卫生要求的工作环境和条件，并采取措施保障劳动者获得职业卫生保护。'),
(1028, 10, '噪声聋', '噪声聋隐患排查', '一般', '《中华人民共和国职业病防治法》', '第二十二条', '用人单位必须采用有效的职业病防护设施，并为劳动者提供个人使用的职业病防护用品。用人单位为劳动者个人提供的职业病防护用品必须符合防治职业病的要求；不符合要求的，不得使用。'),
(1029, 10, '铬鼻病', '铬鼻病隐患排查', '重大', '《中华人民共和国职业病防治法》', '第三十三条', '用人单位与劳动者订立劳动合同（含聘用合同，下同）时，应当将工作过程中可能产生的职业病危害及其后果、职业病防护措施和待遇等如实告知劳动者，并在劳动合同中写明，不得隐瞒或者欺骗。劳动者在已订立劳动合同期间因工作岗位或者工作内容变更，从事与所订立劳动合同中未告知的存在职业病危害的作业时，用人单位应当依照前款规定，向劳动者履行如实告知的义务，并协商变更原劳动合同相关条款。'),
(1030, 10, '牙酸蚀病', '牙酸蚀病隐患排查', '较大', '《中华人民共和国职业病防治法》', '第三十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训，普及职业卫生知识，督促劳动者遵守职业病防治法律、法规、规章和操作规程，指导劳动者正确使用职业病防护设备和个人使用的职业病防护用品。'),
(1031, 10, '爆震聋', '爆震聋隐患排查', '一般', '《工作场所职业卫生管理规定》', '第十二条', '用人单位应当对工作场所进行职业病危害因素检测、评价。检测、评价结果存入用人单位职业卫生档案，定期向所在地卫生健康主管部门报告并向劳动者公布。'),
(1032, 10, '职业性肿瘤', '职业性肿瘤隐患排查', '重大', '《工作场所职业卫生管理规定》', '第十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训。'),
(1033, 10, '石棉所致肺癌', '石棉所致肺癌隐患排查', '较大', '《工作场所有害因素职业接触限值第1部分：化学有害因素》GBZ 2.1-2019', '第4.1条', '工作场所化学有害因素职业接触限值包括时间加权平均容许浓度、短时间接触容许浓度和最高容许浓度三类。'),
(1034, 10, '苯所致白血病', '苯所致白血病隐患排查', '一般', '《工作场所有害因素职业接触限值第2部分：物理因素》GBZ 2.2-2007', '第4.1条', '工作场所物理因素职业接触限值包括噪声、高温、低温、微波辐射、激光辐射、紫外辐射、红外辐射等各类物理因素的限值要求。'),
(1035, 10, '联苯胺所致膀胱癌', '联苯胺所致膀胱癌隐患排查', '重大', '《用人单位职业病危害告知与警示标识管理规范》', '第三条', '用人单位应当将工作场所职业病危害因素和职业病危害后果等以书面形式告知劳动者。'),
(1036, 10, '氯甲醚所致肺癌', '氯甲醚所致肺癌隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1037, 10, '职业性哮喘', '职业性哮喘隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1038, 10, '变态反应性肺泡炎', '变态反应性肺泡炎隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1039, 10, '棉尘病', '棉尘病隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1040, 10, '药物性肺炎', '药物性肺炎隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1041, 10, '劳防用品缺失', '劳防用品缺失隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1042, 10, '防尘口罩不合格', '防尘口罩不合格隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1043, 10, '防毒面具滤毒盒过期', '防毒面具滤毒盒过期隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1044, 10, '防护面罩破损', '防护面罩破损隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1045, 10, '防护眼镜模糊', '防护眼镜模糊隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1046, 10, '防噪耳塞失效', '防噪耳塞失效隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1047, 10, '防噪耳罩损坏', '防噪耳罩损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1048, 10, '防高温服破损', '防高温服破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1049, 10, '防辐射服屏蔽不足', '防辐射服屏蔽不足隐患排查', '一般', '《中华人民共和国职业病防治法》', '第四条', '劳动者依法享有职业卫生保护的权利。用人单位应当为劳动者创造符合国家职业卫生标准和卫生要求的工作环境和条件，并采取措施保障劳动者获得职业卫生保护。'),
(1050, 10, '作业现场通风不良', '作业现场通风不良隐患排查', '重大', '《中华人民共和国职业病防治法》', '第二十二条', '用人单位必须采用有效的职业病防护设施，并为劳动者提供个人使用的职业病防护用品。用人单位为劳动者个人提供的职业病防护用品必须符合防治职业病的要求；不符合要求的，不得使用。'),
(1051, 10, '局部排风失效', '局部排风失效隐患排查', '较大', '《中华人民共和国职业病防治法》', '第三十三条', '用人单位与劳动者订立劳动合同（含聘用合同，下同）时，应当将工作过程中可能产生的职业病危害及其后果、职业病防护措施和待遇等如实告知劳动者，并在劳动合同中写明，不得隐瞒或者欺骗。劳动者在已订立劳动合同期间因工作岗位或者工作内容变更，从事与所订立劳动合同中未告知的存在职业病危害的作业时，用人单位应当依照前款规定，向劳动者履行如实告知的义务，并协商变更原劳动合同相关条款。'),
(1052, 10, '全面通风不足', '全面通风不足隐患排查', '一般', '《中华人民共和国职业病防治法》', '第三十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训，普及职业卫生知识，督促劳动者遵守职业病防治法律、法规、规章和操作规程，指导劳动者正确使用职业病防护设备和个人使用的职业病防护用品。'),
(1053, 10, '通风管道堵塞', '通风管道堵塞隐患排查', '重大', '《工作场所职业卫生管理规定》', '第十二条', '用人单位应当对工作场所进行职业病危害因素检测、评价。检测、评价结果存入用人单位职业卫生档案，定期向所在地卫生健康主管部门报告并向劳动者公布。'),
(1054, 10, '送风口位置不当', '送风口位置不当隐患排查', '较大', '《工作场所职业卫生管理规定》', '第十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训。'),
(1055, 10, '危害告知不到位', '危害告知不到位隐患排查', '一般', '《工作场所有害因素职业接触限值第1部分：化学有害因素》GBZ 2.1-2019', '第4.1条', '工作场所化学有害因素职业接触限值包括时间加权平均容许浓度、短时间接触容许浓度和最高容许浓度三类。'),
(1056, 10, '健康检查未按规定开展', '健康检查未按规定开展隐患排查', '重大', '《工作场所有害因素职业接触限值第2部分：物理因素》GBZ 2.2-2007', '第4.1条', '工作场所物理因素职业接触限值包括噪声、高温、低温、微波辐射、激光辐射、紫外辐射、红外辐射等各类物理因素的限值要求。'),
(1057, 10, '岗前检查缺失', '岗前检查缺失隐患排查', '较大', '《用人单位职业病危害告知与警示标识管理规范》', '第三条', '用人单位应当将工作场所职业病危害因素和职业病危害后果等以书面形式告知劳动者。'),
(1058, 10, '在岗检查超期', '在岗检查超期隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1059, 10, '离岗检查未落实', '离岗检查未落实隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1060, 10, '监护档案不健全', '监护档案不健全隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1061, 10, '危害因素检测未定期开展', '危害因素检测未定期开展隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1062, 10, '检测结果未公示', '检测结果未公示隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1063, 10, '申报不实', '申报不实隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1064, 10, '警示标识缺失', '警示标识缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1065, 10, '中文说明不完整', '中文说明不完整隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1066, 10, '应急救援设施不足', '应急救援设施不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1067, 10, '中毒应急预案缺失', '中毒应急预案缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1068, 10, '急救药品过期', '急救药品过期隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1069, 10, '冲洗设备水压不足', '冲洗设备水压不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1070, 10, '洗眼器损坏', '洗眼器损坏隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1071, 10, '毒物报警器失灵', '毒物报警器失灵隐患排查', '重大', '《中华人民共和国职业病防治法》', '第四条', '劳动者依法享有职业卫生保护的权利。用人单位应当为劳动者创造符合国家职业卫生标准和卫生要求的工作环境和条件，并采取措施保障劳动者获得职业卫生保护。'),
(1072, 10, '报警值设定不当', '报警值设定不当隐患排查', '较大', '《中华人民共和国职业病防治法》', '第二十二条', '用人单位必须采用有效的职业病防护设施，并为劳动者提供个人使用的职业病防护用品。用人单位为劳动者个人提供的职业病防护用品必须符合防治职业病的要求；不符合要求的，不得使用。'),
(1073, 10, '报警器未定期校准', '报警器未定期校准隐患排查', '一般', '《中华人民共和国职业病防治法》', '第三十三条', '用人单位与劳动者订立劳动合同（含聘用合同，下同）时，应当将工作过程中可能产生的职业病危害及其后果、职业病防护措施和待遇等如实告知劳动者，并在劳动合同中写明，不得隐瞒或者欺骗。劳动者在已订立劳动合同期间因工作岗位或者工作内容变更，从事与所订立劳动合同中未告知的存在职业病危害的作业时，用人单位应当依照前款规定，向劳动者履行如实告知的义务，并协商变更原劳动合同相关条款。'),
(1074, 10, '报警系统故障', '报警系统故障隐患排查', '重大', '《中华人民共和国职业病防治法》', '第三十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训，普及职业卫生知识，督促劳动者遵守职业病防治法律、法规、规章和操作规程，指导劳动者正确使用职业病防护设备和个人使用的职业病防护用品。'),
(1075, 10, '诊断程序不合规', '诊断程序不合规隐患排查', '较大', '《工作场所职业卫生管理规定》', '第十二条', '用人单位应当对工作场所进行职业病危害因素检测、评价。检测、评价结果存入用人单位职业卫生档案，定期向所在地卫生健康主管部门报告并向劳动者公布。'),
(1076, 10, '报告不及时', '报告不及时隐患排查', '一般', '《工作场所职业卫生管理规定》', '第十五条', '用人单位应当对劳动者进行上岗前的职业卫生培训和在岗期间的定期职业卫生培训。'),
(1077, 10, '未按规定提供诊断资料', '未按规定提供诊断资料隐患排查', '重大', '《工作场所有害因素职业接触限值第1部分：化学有害因素》GBZ 2.1-2019', '第4.1条', '工作场所化学有害因素职业接触限值包括时间加权平均容许浓度、短时间接触容许浓度和最高容许浓度三类。'),
(1078, 10, '女工禁忌岗位安排不当', '女工禁忌岗位安排不当隐患排查', '较大', '《工作场所有害因素职业接触限值第2部分：物理因素》GBZ 2.2-2007', '第4.1条', '工作场所物理因素职业接触限值包括噪声、高温、低温、微波辐射、激光辐射、紫外辐射、红外辐射等各类物理因素的限值要求。'),
(1079, 10, '未成年工禁忌岗位安排不当', '未成年工禁忌岗位安排不当隐患排查', '一般', '《用人单位职业病危害告知与警示标识管理规范》', '第三条', '用人单位应当将工作场所职业病危害因素和职业病危害后果等以书面形式告知劳动者。'),
(1080, 10, '孕期女工保护不到位', '孕期女工保护不到位隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1081, 11, '校园围墙破损', '校园围墙破损隐患排查', '较大', '《中华人民共和国未成年人保护法》', '第三十五条', '学校、幼儿园应当建立安全管理制度，对未成年人进行安全教育，完善安保设施，配备安保人员，保障未成年人在校、在园期间的人身和财产安全。'),
(1082, 11, '校门未设防冲撞设施', '校门未设防冲撞设施隐患排查', '一般', '《中小学幼儿园安全管理办法》', '第二十四条', '学校应当建立校内安全工作领导机构，实行校长负责制。学校应当设立保卫机构，配备专职或者兼职安全保卫人员，明确其安全保卫职责。'),
(1083, 11, '校园监控盲区', '校园监控盲区隐患排查', '重大', '《中小学幼儿园安全管理办法》', '第三十四条', '学校应当对学生开展安全教育，培养学生的安全意识，提高学生的自我防护能力。学校应当制定突发事件应急预案，并定期组织应急演练。'),
(1084, 11, '监控摄像头模糊', '监控摄像头模糊隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1085, 11, '视频存储时间不足', '视频存储时间不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1086, 11, '校园欺凌行为', '校园欺凌行为隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1087, 11, '学生斗殴事件', '学生斗殴事件隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1088, 11, '校外人员闯入', '校外人员闯入隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1089, 11, '门卫保安脱岗', '门卫保安脱岗隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1090, 11, '访客登记不严格', '访客登记不严格隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1091, 11, '易燃品违规存放实验室', '易燃品违规存放实验室隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1092, 11, '化学实验品管理不规范', '化学实验品管理不规范隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1093, 11, '气体钢瓶固定不牢', '气体钢瓶固定不牢隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1094, 11, '实验室通风不良', '实验室通风不良隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1095, 11, '实验废弃物处置不当', '实验废弃物处置不当隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1096, 11, '实验室用电安全隐患', '实验室用电安全隐患隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1097, 11, '实验室消防不足', '实验室消防不足隐患排查', '一般', '《中华人民共和国未成年人保护法》', '第三十五条', '学校、幼儿园应当建立安全管理制度，对未成年人进行安全教育，完善安保设施，配备安保人员，保障未成年人在校、在园期间的人身和财产安全。'),
(1098, 11, '高压灭菌锅安全失效', '高压灭菌锅安全失效隐患排查', '重大', '《中小学幼儿园安全管理办法》', '第二十四条', '学校应当建立校内安全工作领导机构，实行校长负责制。学校应当设立保卫机构，配备专职或者兼职安全保卫人员，明确其安全保卫职责。'),
(1099, 11, '建筑物墙体裂缝', '建筑物墙体裂缝隐患排查', '较大', '《中小学幼儿园安全管理办法》', '第三十四条', '学校应当对学生开展安全教育，培养学生的安全意识，提高学生的自我防护能力。学校应当制定突发事件应急预案，并定期组织应急演练。'),
(1100, 11, '教学楼台阶破损', '教学楼台阶破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1101, 11, '走廊护栏高度不足', '走廊护栏高度不足隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1102, 11, '楼梯间照明不足', '楼梯间照明不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1103, 11, '教室门窗玻璃破损', '教室门窗玻璃破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1104, 11, '操场设施损坏', '操场设施损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1105, 11, '篮球架松动', '篮球架松动隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1106, 11, '足球门固定不牢', '足球门固定不牢隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1107, 11, '单双杠锈蚀', '单双杠锈蚀隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1108, 11, '跑道地面破损', '跑道地面破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1109, 11, '运动器材老化', '运动器材老化隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1110, 11, '学生食堂食品安全', '学生食堂食品安全隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1111, 11, '食堂食材过期', '食堂食材过期隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1112, 11, '后厨卫生不达标', '后厨卫生不达标隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1113, 11, '餐具消毒不彻底', '餐具消毒不彻底隐患排查', '重大', '《中华人民共和国未成年人保护法》', '第三十五条', '学校、幼儿园应当建立安全管理制度，对未成年人进行安全教育，完善安保设施，配备安保人员，保障未成年人在校、在园期间的人身和财产安全。'),
(1114, 11, '饮用水不达标', '饮用水不达标隐患排查', '较大', '《中小学幼儿园安全管理办法》', '第二十四条', '学校应当建立校内安全工作领导机构，实行校长负责制。学校应当设立保卫机构，配备专职或者兼职安全保卫人员，明确其安全保卫职责。'),
(1115, 11, '校车安全', '校车安全隐患排查', '一般', '《中小学幼儿园安全管理办法》', '第三十四条', '学校应当对学生开展安全教育，培养学生的安全意识，提高学生的自我防护能力。学校应当制定突发事件应急预案，并定期组织应急演练。'),
(1116, 11, '校车超员', '校车超员隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1117, 11, '校车资质过期', '校车资质过期隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1118, 11, '校车驾驶员无证', '校车驾驶员无证隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1119, 11, '校车未按规定路线行驶', '校车未按规定路线行驶隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1120, 11, '校车灭火器缺失', '校车灭火器缺失隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1121, 11, '学生宿舍安全', '学生宿舍安全隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1122, 11, '宿舍私拉电线', '宿舍私拉电线隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1123, 11, '宿舍使用违规电器', '宿舍使用违规电器隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1124, 11, '宿舍易燃物堆放', '宿舍易燃物堆放隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1125, 11, '宿舍消防通道堵塞', '宿舍消防通道堵塞隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1126, 11, '宿舍门锁损坏', '宿舍门锁损坏隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1127, 11, '管理人员配备不足', '管理人员配备不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1128, 11, '夜不归宿管理缺失', '夜不归宿管理缺失隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1129, 11, '校园交通安全', '校园交通安全隐患排查', '较大', '《中华人民共和国未成年人保护法》', '第三十五条', '学校、幼儿园应当建立安全管理制度，对未成年人进行安全教育，完善安保设施，配备安保人员，保障未成年人在校、在园期间的人身和财产安全。'),
(1130, 11, '校内车辆超速', '校内车辆超速隐患排查', '一般', '《中小学幼儿园安全管理办法》', '第二十四条', '学校应当建立校内安全工作领导机构，实行校长负责制。学校应当设立保卫机构，配备专职或者兼职安全保卫人员，明确其安全保卫职责。'),
(1131, 11, '校内人车混行', '校内人车混行隐患排查', '重大', '《中小学幼儿园安全管理办法》', '第三十四条', '学校应当对学生开展安全教育，培养学生的安全意识，提高学生的自我防护能力。学校应当制定突发事件应急预案，并定期组织应急演练。'),
(1132, 11, '停车位占用消防通道', '停车位占用消防通道隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1133, 11, '校园门口交通秩序混乱', '校园门口交通秩序混乱隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1134, 11, '自然灾害防范', '自然灾害防范隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1135, 11, '地震演练未开展', '地震演练未开展隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1136, 11, '防震疏散通道不畅', '防震疏散通道不畅隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1137, 11, '防汛设施不完善', '防汛设施不完善隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1138, 11, '防雷设施损坏', '防雷设施损坏隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1139, 11, '校外活动安全', '校外活动安全隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1140, 11, '集体外出未报备', '集体外出未报备隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1141, 11, '研学旅行预案不完善', '研学旅行预案不完善隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1142, 11, '校外实践防护不足', '校外实践防护不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1143, 11, '心理健康教育', '心理健康教育隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1144, 11, '心理危机干预机制不健全', '心理危机干预机制不健全隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1145, 11, '咨询室配备不足', '咨询室配备不足隐患排查', '一般', '《中华人民共和国未成年人保护法》', '第三十五条', '学校、幼儿园应当建立安全管理制度，对未成年人进行安全教育，完善安保设施，配备安保人员，保障未成年人在校、在园期间的人身和财产安全。'),
(1146, 11, '心理筛查未定期开展', '心理筛查未定期开展隐患排查', '重大', '《中小学幼儿园安全管理办法》', '第二十四条', '学校应当建立校内安全工作领导机构，实行校长负责制。学校应当设立保卫机构，配备专职或者兼职安全保卫人员，明确其安全保卫职责。'),
(1147, 11, '传染病防控', '传染病防控隐患排查', '较大', '《中小学幼儿园安全管理办法》', '第三十四条', '学校应当对学生开展安全教育，培养学生的安全意识，提高学生的自我防护能力。学校应当制定突发事件应急预案，并定期组织应急演练。'),
(1148, 11, '晨午检落实不到位', '晨午检落实不到位隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1149, 11, '因病缺勤追踪不完整', '因病缺勤追踪不完整隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1150, 11, '教室通风消毒不规范', '教室通风消毒不规范隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1151, 11, '隔离观察室不足', '隔离观察室不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1152, 11, '疫情报告不及时', '疫情报告不及时隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1153, 11, '校园周边安全', '校园周边安全隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1154, 11, '周边网吧违规接待学生', '周边网吧违规接待学生隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1155, 11, '周边摊贩食品安全隐患', '周边摊贩食品安全隐患隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1156, 11, '周边治安乱点', '周边治安乱点隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1157, 11, '安全教育', '安全教育隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1158, 11, '课程未落实', '课程未落实隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1159, 11, '知识宣传不到位', '知识宣传不到位隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1160, 11, '疏散演练未定期开展', '疏散演练未定期开展隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1161, 11, '事故应急预案缺失', '事故应急预案缺失隐患排查', '重大', '《中华人民共和国未成年人保护法》', '第三十五条', '学校、幼儿园应当建立安全管理制度，对未成年人进行安全教育，完善安保设施，配备安保人员，保障未成年人在校、在园期间的人身和财产安全。'),
(1162, 11, '管理制度不健全', '管理制度不健全隐患排查', '较大', '《中小学幼儿园安全管理办法》', '第二十四条', '学校应当建立校内安全工作领导机构，实行校长负责制。学校应当设立保卫机构，配备专职或者兼职安全保卫人员，明确其安全保卫职责。'),
(1163, 11, '责任人不明确', '责任人不明确隐患排查', '一般', '《中小学幼儿园安全管理办法》', '第三十四条', '学校应当对学生开展安全教育，培养学生的安全意识，提高学生的自我防护能力。学校应当制定突发事件应急预案，并定期组织应急演练。'),
(1164, 11, '校内施工区域防护不足', '校内施工区域防护不足隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1165, 11, '施工现场未隔离', '施工现场未隔离隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1166, 11, '施工车辆进出管理不严', '施工车辆进出管理不严隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1167, 11, '施工噪音影响教学', '施工噪音影响教学隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1168, 11, '校园网络安全', '校园网络安全隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1169, 11, '网络不良信息传播', '网络不良信息传播隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1170, 11, '学生个人信息泄露', '学生个人信息泄露隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1171, 11, '学校网站安全漏洞', '学校网站安全漏洞隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1172, 11, '家校沟通机制不健全', '家校沟通机制不健全隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1173, 11, '异常情况通报不及时', '异常情况通报不及时隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1174, 11, '家长安全告知不到位', '家长安全告知不到位隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1175, 12, '小区门禁损坏', '小区门禁损坏隐患排查', '一般', '《中华人民共和国消防法》', '第十六条', '机关、团体、企业、事业等单位应当履行下列消防安全职责：（一）落实消防安全责任制，制定本单位的消防安全制度、消防安全操作规程，制定灭火和应急疏散预案；（二）按照国家标准、行业标准配置消防设施、器材，设置消防安全标志，并定期组织检验、维修，确保完好有效；（三）对建筑消防设施每年至少进行一次全面检测，确保完好有效，检测记录应当完整准确，存档备查；（四）保障疏散通道、安全出口、消防车通道畅通，保证防火防烟分区、防火间距符合消防技术标准；（五）组织防火检查，及时消除火灾隐患；（六）组织进行有针对性的消防演练；（七）法律、法规规定的其他消防安全职责。'),
(1176, 12, '楼道堆物', '楼道堆物隐患排查', '重大', '《中华人民共和国消防法》', '第二十七条', '电器产品、燃气用具的产品标准，应当符合消防安全的要求。电器产品、燃气用具的安装、使用及其线路、管路的设计、敷设、维护保养、检测，必须符合消防技术标准和管理规定。'),
(1177, 12, '电梯故障困人', '电梯故障困人隐患排查', '较大', '《中华人民共和国消防法》', '第二十八条', '任何单位、个人不得损坏、挪用或者擅自拆除、停用消防设施、器材，不得埋压、圈占、遮挡消火栓或者占用防火间距，不得占用、堵塞、封闭疏散通道、安全出口、消防车通道。人员密集场所的门窗不得设置影响逃生和灭火救援的障碍物。'),
(1178, 12, '高空抛物隐患', '高空抛物隐患隐患排查', '一般', '《中华人民共和国消防法》', '第二十九条', '负责公共消防设施维护管理的单位，应当保持消防供水、消防通信、消防车通道等公共消防设施的完好有效。在修建道路以及停电、停水、截断通信线路时有可能影响消防队灭火救援的，有关单位必须事先通知当地消防救援机构。'),
(1179, 12, '外墙脱落', '外墙脱落隐患排查', '重大', '《中华人民共和国消防法》', '第四十四条', '任何人发现火灾都应当立即报警。任何单位、个人都应当无偿为报警提供便利，不得阻拦报警。严禁谎报火警。人员密集场所发生火灾，该场所的现场工作人员应当立即组织、引导在场人员疏散。任何单位发生火灾，必须立即组织力量扑救。邻近单位应当给予支援。'),
(1180, 12, '小区监控故障', '小区监控故障隐患排查', '较大', '《中华人民共和国消防法》', '第六十条', '单位违反本法规定，有下列行为之一的，责令改正，处五千元以上五万元以下罚款：（一）消防设施、器材或者消防安全标志的配置、设置不符合国家标准、行业标准，或者未保持完好有效的；（二）损坏、挪用或者擅自拆除、停用消防设施、器材的；（三）占用、堵塞、封闭疏散通道、安全出口或者有其他妨碍安全疏散行为的；（四）埋压、圈占、遮挡消火栓或者占用防火间距的；（五）占用、堵塞、封闭消防车通道，妨碍消防车通行的。'),
(1181, 12, '地下车库积水', '地下车库积水隐患排查', '一般', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第2.1.1条', '高层建筑：建筑高度大于27m的住宅建筑和建筑高度大于24m的非单层厂房、仓库和其他民用建筑。'),
(1182, 12, '化粪池满溢', '化粪池满溢隐患排查', '重大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第5.5.8条', '公共建筑内每个防火分区或一个防火分区的每个楼层，其安全出口的数量应经计算确定，且不应少于2个。设置1个安全出口或1部疏散楼梯的公共建筑应符合下列条件之一：（1）除托儿所、幼儿园外，建筑面积不大于200㎡且人数不超过50人的单层公共建筑或多层公共建筑的首层。'),
(1183, 12, '小区道路破损', '小区道路破损隐患排查', '较大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第5.5.15条', '公共建筑内房间的疏散门数量应经计算确定且不应少于2个。除托儿所、幼儿园、老年人建筑、医疗建筑、教学建筑内位于走道尽端的房间外，符合下列条件之一的房间可设置1个疏散门：（1）位于两个安全出口之间或袋形走道两侧的房间，对于托儿所、幼儿园、老年人建筑，建筑面积不大于50㎡；对于医疗建筑、教学建筑，建筑面积不大于75㎡；对于其他建筑或场所，建筑面积不大于120㎡。'),
(1184, 12, '绿化枯萎', '绿化枯萎隐患排查', '一般', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第6.4.10条', '疏散走道在防火分区处应设置常开甲级防火门。'),
(1185, 12, '小区照明不足', '小区照明不足隐患排查', '重大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第6.5.1条', '防火门的设置应符合下列规定：1.设置在建筑内经常有人通行处的防火门宜采用常开防火门。常开防火门应能在火灾时自行关闭，并应具有信号反馈的功能。2.除允许设置常开防火门的位置外，其他位置的防火门均应采用常闭防火门。常闭防火门应在其明显位置设置"保持防火门关闭"等提示标识。3.除管井检修门和住宅的户门外，防火门应具有自行关闭功能。'),
(1186, 12, '小区围墙破损', '小区围墙破损隐患排查', '较大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第8.3.1条', '下列建筑或场所应设置火灾自动报警系统：1.任一层建筑面积大于1500㎡或总建筑面积大于3000㎡的制鞋、制衣、玩具、电子等类似用途的厂房；2.每座占地面积大于1000㎡的棉、毛、丝、麻、化纤及其制品的仓库，占地面积大于500㎡的卷烟仓库；3.任一层建筑面积大于1500㎡或总建筑面积大于3000㎡的商店、展览、财贸金融、客运和货运等类似用途的建筑；4.图书或文物的珍藏库，每座藏书超过50万册的图书馆，重要的档案馆；5.地市级及以上广播电视建筑、邮政建筑、电信建筑；6.歌舞娱乐放映游艺场所；7.净高大于2.6m且可燃物较多的技术夹层，净高大于0.8m且有可燃物的闷顶或吊顶内；8.电子信息系统的主机房及其控制室等。'),
(1187, 12, '健身器材损坏', '健身器材损坏隐患排查', '一般', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第8.3.3条', '除本规范另有规定和不宜用水保护或灭火的场所外，下列高层民用建筑或场所应设置自动灭火系统：1.一类高层公共建筑（除游泳池、溜冰场外）及其地下、半地下室；2.二类高层公共建筑及其地下、半地下室的公共活动用房、走道、办公室和旅馆的客房、可燃物品库房、自动扶梯底部；3.高层民用建筑内的歌舞娱乐放映游艺场所；4.建筑高度大于100m的住宅建筑。'),
(1188, 12, '儿童游乐设施损坏', '儿童游乐设施损坏隐患排查', '重大', '《建筑防火通用规范》GB 55037-2022', '第2.0.1条', '建筑的防火设计应遵循"预防为主、防消结合"的消防工作方针，针对建筑的实际使用功能、火灾危险性、火灾荷载、人员特征、建筑高度和体量等因素，合理确定建筑的防火措施，保障建筑消防安全。'),
(1189, 12, '小区消防通道堵塞', '小区消防通道堵塞隐患排查', '较大', '《消防设施通用规范》GB 55036-2022', '第2.0.1条', '消防给水与灭火设施应满足在火灾延续时间内持续供水和持续灭火的要求，消防水源应安全可靠，消防给水设施应保证在火灾时能正常启动和运行。'),
(1190, 12, '小区消火栓无水', '小区消火栓无水隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1191, 12, '灭火器过期', '灭火器过期隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1192, 12, '电动车进楼道', '电动车进楼道隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1193, 12, '飞线充电', '飞线充电隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1194, 12, '楼道照明损坏', '楼道照明损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1195, 12, '单元门损坏', '单元门损坏隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1196, 12, '对讲系统故障', '对讲系统故障隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1197, 12, '快递柜损坏', '快递柜损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1198, 12, '小区井盖破损', '小区井盖破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1199, 12, '小区排水不畅', '小区排水不畅隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1200, 12, '垃圾收集点脏乱', '垃圾收集点脏乱隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1201, 12, '垃圾桶破损', '垃圾桶破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1202, 12, '小区噪音扰民', '小区噪音扰民隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1203, 12, '小区流浪狗隐患', '小区流浪狗隐患隐患排查', '重大', '《中华人民共和国消防法》', '第十六条', '机关、团体、企业、事业等单位应当履行下列消防安全职责：（一）落实消防安全责任制，制定本单位的消防安全制度、消防安全操作规程，制定灭火和应急疏散预案；（二）按照国家标准、行业标准配置消防设施、器材，设置消防安全标志，并定期组织检验、维修，确保完好有效；（三）对建筑消防设施每年至少进行一次全面检测，确保完好有效，检测记录应当完整准确，存档备查；（四）保障疏散通道、安全出口、消防车通道畅通，保证防火防烟分区、防火间距符合消防技术标准；（五）组织防火检查，及时消除火灾隐患；（六）组织进行有针对性的消防演练；（七）法律、法规规定的其他消防安全职责。'),
(1204, 12, '小区安保巡查缺位', '小区安保巡查缺位隐患排查', '较大', '《中华人民共和国消防法》', '第二十七条', '电器产品、燃气用具的产品标准，应当符合消防安全的要求。电器产品、燃气用具的安装、使用及其线路、管路的设计、敷设、维护保养、检测，必须符合消防技术标准和管理规定。'),
(1205, 12, '外来人员随意进出', '外来人员随意进出隐患排查', '一般', '《中华人民共和国消防法》', '第二十八条', '任何单位、个人不得损坏、挪用或者擅自拆除、停用消防设施、器材，不得埋压、圈占、遮挡消火栓或者占用防火间距，不得占用、堵塞、封闭疏散通道、安全出口、消防车通道。人员密集场所的门窗不得设置影响逃生和灭火救援的障碍物。'),
(1206, 12, '小区停车位被占', '小区停车位被占隐患排查', '重大', '《中华人民共和国消防法》', '第二十九条', '负责公共消防设施维护管理的单位，应当保持消防供水、消防通信、消防车通道等公共消防设施的完好有效。在修建道路以及停电、停水、截断通信线路时有可能影响消防队灭火救援的，有关单位必须事先通知当地消防救援机构。'),
(1207, 12, '物业服务质量差', '物业服务质量差隐患排查', '较大', '《中华人民共和国消防法》', '第四十四条', '任何人发现火灾都应当立即报警。任何单位、个人都应当无偿为报警提供便利，不得阻拦报警。严禁谎报火警。人员密集场所发生火灾，该场所的现场工作人员应当立即组织、引导在场人员疏散。任何单位发生火灾，必须立即组织力量扑救。邻近单位应当给予支援。'),
(1208, 12, '物业费收支不透明', '物业费收支不透明隐患排查', '一般', '《中华人民共和国消防法》', '第六十条', '单位违反本法规定，有下列行为之一的，责令改正，处五千元以上五万元以下罚款：（一）消防设施、器材或者消防安全标志的配置、设置不符合国家标准、行业标准，或者未保持完好有效的；（二）损坏、挪用或者擅自拆除、停用消防设施、器材的；（三）占用、堵塞、封闭疏散通道、安全出口或者有其他妨碍安全疏散行为的；（四）埋压、圈占、遮挡消火栓或者占用防火间距的；（五）占用、堵塞、封闭消防车通道，妨碍消防车通行的。'),
(1209, 12, '公共收益未公示', '公共收益未公示隐患排查', '重大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第2.1.1条', '高层建筑：建筑高度大于27m的住宅建筑和建筑高度大于24m的非单层厂房、仓库和其他民用建筑。'),
(1210, 12, '小区监控盲区', '小区监控盲区隐患排查', '较大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第5.5.8条', '公共建筑内每个防火分区或一个防火分区的每个楼层，其安全出口的数量应经计算确定，且不应少于2个。设置1个安全出口或1部疏散楼梯的公共建筑应符合下列条件之一：（1）除托儿所、幼儿园外，建筑面积不大于200㎡且人数不超过50人的单层公共建筑或多层公共建筑的首层。'),
(1211, 12, '配电房未上锁', '配电房未上锁隐患排查', '一般', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第5.5.15条', '公共建筑内房间的疏散门数量应经计算确定且不应少于2个。除托儿所、幼儿园、老年人建筑、医疗建筑、教学建筑内位于走道尽端的房间外，符合下列条件之一的房间可设置1个疏散门：（1）位于两个安全出口之间或袋形走道两侧的房间，对于托儿所、幼儿园、老年人建筑，建筑面积不大于50㎡；对于医疗建筑、教学建筑，建筑面积不大于75㎡；对于其他建筑或场所，建筑面积不大于120㎡。'),
(1212, 12, '水泵房设备老化', '水泵房设备老化隐患排查', '重大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第6.4.10条', '疏散走道在防火分区处应设置常开甲级防火门。'),
(1213, 12, '二次供水水质不达标', '二次供水水质不达标隐患排查', '较大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第6.5.1条', '防火门的设置应符合下列规定：1.设置在建筑内经常有人通行处的防火门宜采用常开防火门。常开防火门应能在火灾时自行关闭，并应具有信号反馈的功能。2.除允许设置常开防火门的位置外，其他位置的防火门均应采用常闭防火门。常闭防火门应在其明显位置设置"保持防火门关闭"等提示标识。3.除管井检修门和住宅的户门外，防火门应具有自行关闭功能。'),
(1214, 12, '小区水池未清洗', '小区水池未清洗隐患排查', '一般', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第8.3.1条', '下列建筑或场所应设置火灾自动报警系统：1.任一层建筑面积大于1500㎡或总建筑面积大于3000㎡的制鞋、制衣、玩具、电子等类似用途的厂房；2.每座占地面积大于1000㎡的棉、毛、丝、麻、化纤及其制品的仓库，占地面积大于500㎡的卷烟仓库；3.任一层建筑面积大于1500㎡或总建筑面积大于3000㎡的商店、展览、财贸金融、客运和货运等类似用途的建筑；4.图书或文物的珍藏库，每座藏书超过50万册的图书馆，重要的档案馆；5.地市级及以上广播电视建筑、邮政建筑、电信建筑；6.歌舞娱乐放映游艺场所；7.净高大于2.6m且可燃物较多的技术夹层，净高大于0.8m且有可燃物的闷顶或吊顶内；8.电子信息系统的主机房及其控制室等。'),
(1215, 12, '小区电梯年检过期', '小区电梯年检过期隐患排查', '重大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第8.3.3条', '除本规范另有规定和不宜用水保护或灭火的场所外，下列高层民用建筑或场所应设置自动灭火系统：1.一类高层公共建筑（除游泳池、溜冰场外）及其地下、半地下室；2.二类高层公共建筑及其地下、半地下室的公共活动用房、走道、办公室和旅馆的客房、可燃物品库房、自动扶梯底部；3.高层民用建筑内的歌舞娱乐放映游艺场所；4.建筑高度大于100m的住宅建筑。'),
(1216, 12, '电梯维保不到位', '电梯维保不到位隐患排查', '较大', '《建筑防火通用规范》GB 55037-2022', '第2.0.1条', '建筑的防火设计应遵循"预防为主、防消结合"的消防工作方针，针对建筑的实际使用功能、火灾危险性、火灾荷载、人员特征、建筑高度和体量等因素，合理确定建筑的防火措施，保障建筑消防安全。'),
(1217, 12, '消防设施维保缺失', '消防设施维保缺失隐患排查', '一般', '《消防设施通用规范》GB 55036-2022', '第2.0.1条', '消防给水与灭火设施应满足在火灾延续时间内持续供水和持续灭火的要求，消防水源应安全可靠，消防给水设施应保证在火灾时能正常启动和运行。'),
(1218, 12, '消防通道被私家车占用', '消防通道被私家车占用隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1219, 12, '垃圾分类不到位', '垃圾分类不到位隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1220, 12, '装修垃圾乱堆放', '装修垃圾乱堆放隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1221, 12, '大件垃圾未及时清运', '大件垃圾未及时清运隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1222, 12, '废弃家具占用公共区域', '废弃家具占用公共区域隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1223, 12, '小区违规搭建', '小区违规搭建隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1224, 12, '业主圈占公共区域', '业主圈占公共区域隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1225, 12, '一楼庭院违建', '一楼庭院违建隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1226, 12, '楼顶违建', '楼顶违建隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1227, 12, '小区违章建筑', '小区违章建筑隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1228, 12, '宠物扰民', '宠物扰民隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1229, 12, '养狗未牵绳', '养狗未牵绳隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1230, 12, '宠物粪便未清理', '宠物粪便未清理隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1231, 12, '小区养鸡养鸭', '小区养鸡养鸭隐患排查', '较大', '《中华人民共和国消防法》', '第十六条', '机关、团体、企业、事业等单位应当履行下列消防安全职责：（一）落实消防安全责任制，制定本单位的消防安全制度、消防安全操作规程，制定灭火和应急疏散预案；（二）按照国家标准、行业标准配置消防设施、器材，设置消防安全标志，并定期组织检验、维修，确保完好有效；（三）对建筑消防设施每年至少进行一次全面检测，确保完好有效，检测记录应当完整准确，存档备查；（四）保障疏散通道、安全出口、消防车通道畅通，保证防火防烟分区、防火间距符合消防技术标准；（五）组织防火检查，及时消除火灾隐患；（六）组织进行有针对性的消防演练；（七）法律、法规规定的其他消防安全职责。'),
(1232, 12, '小区车辆超速行驶', '小区车辆超速行驶隐患排查', '一般', '《中华人民共和国消防法》', '第二十七条', '电器产品、燃气用具的产品标准，应当符合消防安全的要求。电器产品、燃气用具的安装、使用及其线路、管路的设计、敷设、维护保养、检测，必须符合消防技术标准和管理规定。'),
(1233, 12, '小区人车混行道', '小区人车混行道隐患排查', '重大', '《中华人民共和国消防法》', '第二十八条', '任何单位、个人不得损坏、挪用或者擅自拆除、停用消防设施、器材，不得埋压、圈占、遮挡消火栓或者占用防火间距，不得占用、堵塞、封闭疏散通道、安全出口、消防车通道。人员密集场所的门窗不得设置影响逃生和灭火救援的障碍物。'),
(1234, 12, '小区入口视线遮挡', '小区入口视线遮挡隐患排查', '较大', '《中华人民共和国消防法》', '第二十九条', '负责公共消防设施维护管理的单位，应当保持消防供水、消防通信、消防车通道等公共消防设施的完好有效。在修建道路以及停电、停水、截断通信线路时有可能影响消防队灭火救援的，有关单位必须事先通知当地消防救援机构。'),
(1235, 12, '小区标识缺失', '小区标识缺失隐患排查', '一般', '《中华人民共和国消防法》', '第四十四条', '任何人发现火灾都应当立即报警。任何单位、个人都应当无偿为报警提供便利，不得阻拦报警。严禁谎报火警。人员密集场所发生火灾，该场所的现场工作人员应当立即组织、引导在场人员疏散。任何单位发生火灾，必须立即组织力量扑救。邻近单位应当给予支援。'),
(1236, 12, '物业应急响应不及时', '物业应急响应不及时隐患排查', '重大', '《中华人民共和国消防法》', '第六十条', '单位违反本法规定，有下列行为之一的，责令改正，处五千元以上五万元以下罚款：（一）消防设施、器材或者消防安全标志的配置、设置不符合国家标准、行业标准，或者未保持完好有效的；（二）损坏、挪用或者擅自拆除、停用消防设施、器材的；（三）占用、堵塞、封闭疏散通道、安全出口或者有其他妨碍安全疏散行为的；（四）埋压、圈占、遮挡消火栓或者占用防火间距的；（五）占用、堵塞、封闭消防车通道，妨碍消防车通行的。'),
(1237, 12, '小区应急预案缺失', '小区应急预案缺失隐患排查', '较大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第2.1.1条', '高层建筑：建筑高度大于27m的住宅建筑和建筑高度大于24m的非单层厂房、仓库和其他民用建筑。'),
(1238, 12, '灾情预警不到位', '灾情预警不到位隐患排查', '一般', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第5.5.8条', '公共建筑内每个防火分区或一个防火分区的每个楼层，其安全出口的数量应经计算确定，且不应少于2个。设置1个安全出口或1部疏散楼梯的公共建筑应符合下列条件之一：（1）除托儿所、幼儿园外，建筑面积不大于200㎡且人数不超过50人的单层公共建筑或多层公共建筑的首层。'),
(1239, 12, '老年活动设施不足', '老年活动设施不足隐患排查', '重大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第5.5.15条', '公共建筑内房间的疏散门数量应经计算确定且不应少于2个。除托儿所、幼儿园、老年人建筑、医疗建筑、教学建筑内位于走道尽端的房间外，符合下列条件之一的房间可设置1个疏散门：（1）位于两个安全出口之间或袋形走道两侧的房间，对于托儿所、幼儿园、老年人建筑，建筑面积不大于50㎡；对于医疗建筑、教学建筑，建筑面积不大于75㎡；对于其他建筑或场所，建筑面积不大于120㎡。'),
(1240, 12, '休闲座椅损坏', '休闲座椅损坏隐患排查', '较大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第6.4.10条', '疏散走道在防火分区处应设置常开甲级防火门。'),
(1241, 12, '小区健身步道破损', '小区健身步道破损隐患排查', '一般', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第6.5.1条', '防火门的设置应符合下列规定：1.设置在建筑内经常有人通行处的防火门宜采用常开防火门。常开防火门应能在火灾时自行关闭，并应具有信号反馈的功能。2.除允许设置常开防火门的位置外，其他位置的防火门均应采用常闭防火门。常闭防火门应在其明显位置设置"保持防火门关闭"等提示标识。3.除管井检修门和住宅的户门外，防火门应具有自行关闭功能。'),
(1242, 12, '小区景观水池无安全防护', '小区景观水池无安全防护隐患排查', '重大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第8.3.1条', '下列建筑或场所应设置火灾自动报警系统：1.任一层建筑面积大于1500㎡或总建筑面积大于3000㎡的制鞋、制衣、玩具、电子等类似用途的厂房；2.每座占地面积大于1000㎡的棉、毛、丝、麻、化纤及其制品的仓库，占地面积大于500㎡的卷烟仓库；3.任一层建筑面积大于1500㎡或总建筑面积大于3000㎡的商店、展览、财贸金融、客运和货运等类似用途的建筑；4.图书或文物的珍藏库，每座藏书超过50万册的图书馆，重要的档案馆；5.地市级及以上广播电视建筑、邮政建筑、电信建筑；6.歌舞娱乐放映游艺场所；7.净高大于2.6m且可燃物较多的技术夹层，净高大于0.8m且有可燃物的闷顶或吊顶内；8.电子信息系统的主机房及其控制室等。'),
(1243, 12, '小区广告牌松动', '小区广告牌松动隐患排查', '较大', '《建筑设计防火规范》GB 50016-2014（2018年版）', '第8.3.3条', '除本规范另有规定和不宜用水保护或灭火的场所外，下列高层民用建筑或场所应设置自动灭火系统：1.一类高层公共建筑（除游泳池、溜冰场外）及其地下、半地下室；2.二类高层公共建筑及其地下、半地下室的公共活动用房、走道、办公室和旅馆的客房、可燃物品库房、自动扶梯底部；3.高层民用建筑内的歌舞娱乐放映游艺场所；4.建筑高度大于100m的住宅建筑。'),
(1244, 12, '小区路灯杆倾斜', '小区路灯杆倾斜隐患排查', '一般', '《建筑防火通用规范》GB 55037-2022', '第2.0.1条', '建筑的防火设计应遵循"预防为主、防消结合"的消防工作方针，针对建筑的实际使用功能、火灾危险性、火灾荷载、人员特征、建筑高度和体量等因素，合理确定建筑的防火措施，保障建筑消防安全。'),
(1245, 12, '小区线路杂乱', '小区线路杂乱隐患排查', '重大', '《消防设施通用规范》GB 55036-2022', '第2.0.1条', '消防给水与灭火设施应满足在火灾延续时间内持续供水和持续灭火的要求，消防水源应安全可靠，消防给水设施应保证在火灾时能正常启动和运行。'),
(1246, 12, '小区弱电井盖缺失', '小区弱电井盖缺失隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1247, 12, '小区消防演练未开展', '小区消防演练未开展隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1248, 12, '小区安全宣传不到位', '小区安全宣传不到位隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1249, 12, '物业安全检查敷衍', '物业安全检查敷衍隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1250, 12, '小区业主大会召开不规范', '小区业主大会召开不规范隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1251, 12, '业委会选举不规范', '业委会选举不规范隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1252, 12, '物业合同未公示', '物业合同未公示隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1253, 13, '机械防护罩缺失', '机械防护罩缺失隐患排查', '一般', '《生产设备安全卫生设计总则》GB 5083-1999', '第2.1条', '生产设备的安全卫生设计应遵循安全第一、预防为主的方针，采取有效措施，防止生产设备在正常使用和可预见的误操作情况下对人员造成伤害。'),
(1254, 13, '紧急停止按钮失效', '紧急停止按钮失效隐患排查', '重大', '《生产设备安全卫生设计总则》GB 5083-1999', '第3.3条', '生产设备上容易发生危险的部位，必须配置安全防护装置。安全防护装置应满足以下要求：（1）使操作者不能接触到危险部位；（2）在危险部位出现危险时，能自动停机或发出报警信号；（3）安全防护装置本身不应造成新的危险。'),
(1255, 13, '传动装置未防护', '传动装置未防护隐患排查', '较大', '《机械安全防护装置固定式和活动式防护装置设计与制造一般要求》GB/T 8196-2018', '第4.1条', '防护装置应能防止人员进入危险区，并应满足以下要求：（1）结构坚固耐用；（2）不增加任何附加危险；（3）不易被旁路或禁用；（4）与机器运转联锁；（5）满足机器使用环境的要求。'),
(1256, 13, '机械夹伤风险', '机械夹伤风险隐患排查', '一般', '《机械安全急停装置设计原则》GB/T 16754-2008', '第5.1条', '每台机器均应装有一个或多个急停装置，使正在发生的危险能够被中止。急停装置应易于识别、清晰可见、便于操作。'),
(1257, 13, '旋转部件卷入风险', '旋转部件卷入风险隐患排查', '重大', '《磨削机械安全规程》GB 4674-2009', '第4.1条', '磨削机械的砂轮防护罩应能有效地罩住砂轮，防护罩的开口角度和护板尺寸应符合本标准的规定。'),
(1258, 13, '冲压设备安全光幕失效', '冲压设备安全光幕失效隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1259, 13, '剪切机防护装置缺失', '剪切机防护装置缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1260, 13, '锯床防护罩破损', '锯床防护罩破损隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1261, 13, '砂轮机防护罩缺失', '砂轮机防护罩缺失隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1262, 13, '皮带输送机急停拉绳损坏', '皮带输送机急停拉绳损坏隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1263, 13, '皮带跑偏', '皮带跑偏隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1264, 13, '传动链条防护罩缺失', '传动链条防护罩缺失隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1265, 13, '齿轮防护罩缺失', '齿轮防护罩缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1266, 13, '联轴器防护罩缺失', '联轴器防护罩缺失隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1267, 13, '飞轮防护罩缺失', '飞轮防护罩缺失隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1268, 13, '机械联锁装置失效', '机械联锁装置失效隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1269, 13, '双手启动按钮失效', '双手启动按钮失效隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1270, 13, '机械手安全防护不足', '机械手安全防护不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1271, 13, '压机滑块防坠落装置失效', '压机滑块防坠落装置失效隐患排查', '一般', '《生产设备安全卫生设计总则》GB 5083-1999', '第2.1条', '生产设备的安全卫生设计应遵循安全第一、预防为主的方针，采取有效措施，防止生产设备在正常使用和可预见的误操作情况下对人员造成伤害。'),
(1272, 13, '机床卡盘防护不足', '机床卡盘防护不足隐患排查', '重大', '《生产设备安全卫生设计总则》GB 5083-1999', '第3.3条', '生产设备上容易发生危险的部位，必须配置安全防护装置。安全防护装置应满足以下要求：（1）使操作者不能接触到危险部位；（2）在危险部位出现危险时，能自动停机或发出报警信号；（3）安全防护装置本身不应造成新的危险。'),
(1273, 13, '磨床冷却液飞溅', '磨床冷却液飞溅隐患排查', '较大', '《机械安全防护装置固定式和活动式防护装置设计与制造一般要求》GB/T 8196-2018', '第4.1条', '防护装置应能防止人员进入危险区，并应满足以下要求：（1）结构坚固耐用；（2）不增加任何附加危险；（3）不易被旁路或禁用；（4）与机器运转联锁；（5）满足机器使用环境的要求。'),
(1274, 13, '锻造设备防护不足', '锻造设备防护不足隐患排查', '一般', '《机械安全急停装置设计原则》GB/T 16754-2008', '第5.1条', '每台机器均应装有一个或多个急停装置，使正在发生的危险能够被中止。急停装置应易于识别、清晰可见、便于操作。'),
(1275, 13, '铸造设备浇注区未隔离', '铸造设备浇注区未隔离隐患排查', '重大', '《磨削机械安全规程》GB 4674-2009', '第4.1条', '磨削机械的砂轮防护罩应能有效地罩住砂轮，防护罩的开口角度和护板尺寸应符合本标准的规定。'),
(1276, 13, '焊接作业区防火措施不足', '焊接作业区防火措施不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1277, 13, '电焊机接地不良', '电焊机接地不良隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1278, 13, '焊接面罩破损', '焊接面罩破损隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1279, 13, '气焊气瓶间距不足', '气焊气瓶间距不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1280, 13, '乙炔回火防止器失效', '乙炔回火防止器失效隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1281, 13, '压缩空气吹扫伤人风险', '压缩空气吹扫伤人风险隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1282, 13, '液压系统超压', '液压系统超压隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1283, 13, '液压管接头松动', '液压管接头松动隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1284, 13, '液压油泄漏', '液压油泄漏隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1285, 13, '压缩空气管路爆裂', '压缩空气管路爆裂隐患排查', '较大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1286, 13, '气动元件密封失效', '气动元件密封失效隐患排查', '一般', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1287, 13, '压力机超载运行', '压力机超载运行隐患排查', '重大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1288, 13, '冲压模具固定不牢', '冲压模具固定不牢隐患排查', '较大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1289, 13, '机械设备噪音超标', '机械设备噪音超标隐患排查', '一般', '《生产设备安全卫生设计总则》GB 5083-1999', '第2.1条', '生产设备的安全卫生设计应遵循安全第一、预防为主的方针，采取有效措施，防止生产设备在正常使用和可预见的误操作情况下对人员造成伤害。'),
(1290, 13, '加工中心切屑飞溅', '加工中心切屑飞溅隐患排查', '重大', '《生产设备安全卫生设计总则》GB 5083-1999', '第3.3条', '生产设备上容易发生危险的部位，必须配置安全防护装置。安全防护装置应满足以下要求：（1）使操作者不能接触到危险部位；（2）在危险部位出现危险时，能自动停机或发出报警信号；（3）安全防护装置本身不应造成新的危险。'),
(1291, 13, '机械加工粉尘积聚', '机械加工粉尘积聚隐患排查', '较大', '《机械安全防护装置固定式和活动式防护装置设计与制造一般要求》GB/T 8196-2018', '第4.1条', '防护装置应能防止人员进入危险区，并应满足以下要求：（1）结构坚固耐用；（2）不增加任何附加危险；（3）不易被旁路或禁用；（4）与机器运转联锁；（5）满足机器使用环境的要求。'),
(1292, 13, '机械设备维修未断电挂牌', '机械设备维修未断电挂牌隐患排查', '一般', '《机械安全急停装置设计原则》GB/T 16754-2008', '第5.1条', '每台机器均应装有一个或多个急停装置，使正在发生的危险能够被中止。急停装置应易于识别、清晰可见、便于操作。'),
(1293, 13, '机械设备带病运行', '机械设备带病运行隐患排查', '重大', '《磨削机械安全规程》GB 4674-2009', '第4.1条', '磨削机械的砂轮防护罩应能有效地罩住砂轮，防护罩的开口角度和护板尺寸应符合本标准的规定。'),
(1294, 13, '机械设备超速运行', '机械设备超速运行隐患排查', '较大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1295, 13, '机械设备安全距离不足', '机械设备安全距离不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1296, 13, '机械设备操作空间不足', '机械设备操作空间不足隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1297, 13, '机械设备基础松动', '机械设备基础松动隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1298, 13, '机械设备振动超标', '机械设备振动超标隐患排查', '一般', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1299, 13, '润滑系统故障造成磨损', '润滑系统故障造成磨损隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1300, 13, '设备老化报废未及时更换', '设备老化报废未及时更换隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1301, 13, '新设备未验收即投入使用', '新设备未验收即投入使用隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1302, 14, '化工反应釜超温超压', '化工反应釜超温超压隐患排查', '重大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1303, 14, '反应釜搅拌桨脱落', '反应釜搅拌桨脱落隐患排查', '较大', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1304, 14, '反应釜密封泄漏', '反应釜密封泄漏隐患排查', '一般', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。'),
(1305, 14, '化工管道腐蚀穿孔', '化工管道腐蚀穿孔隐患排查', '重大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.2.1条', '化工企业的建（构）筑物、设备、设施等的防火间距应符合现行国家标准《建筑设计防火规范》GB 50016、《石油化工企业设计防火标准》GB 50160等标准的规定。'),
(1306, 14, '化工管道法兰泄漏', '化工管道法兰泄漏隐患排查', '较大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.3.1条', '化工装置的安全设施应符合下列规定：（1）可能发生超压的设备应设置安全阀；（2）可能发生真空的设备应设置真空破坏阀；（3）可能发生火灾的设备应设置灭火设施；（4）可能发生爆炸的设备应设置防爆泄压设施。'),
(1307, 14, '化工储罐液位计失灵', '化工储罐液位计失灵隐患排查', '一般', '《石油化工企业设计防火标准》GB 50160-2008（2018年版）', '第4.2.2条', '石油化工企业的生产区、储存设施区、公用工程设施区、辅助生产设施区、行政办公区等功能分区，应根据火灾危险性、爆炸危险性和环保要求等合理布置。'),
(1308, 14, '化工储罐呼吸阀堵塞', '化工储罐呼吸阀堵塞隐患排查', '重大', '《石油化工可燃气体和有毒气体检测报警设计标准》GB/T 50493-2019', '第3.0.1条', '石油化工生产装置、储运设施等场所应设置可燃气体和有毒气体检测报警系统，用于检测生产过程中泄漏或积聚的可燃气体或有毒气体，并在气体浓度达到设定值时发出报警信号。'),
(1309, 14, '化工储罐防雷接地损坏', '化工储罐防雷接地损坏隐患排查', '较大', '《化工建设项目安全设计管理导则》AQ/T 3033-2022', '第8.1条', '化工建设项目应对工艺过程进行危险与可操作性分析，识别工艺过程中的危险与可操作性问题，并提出相应的安全措施。'),
(1310, 14, '化工泵机械密封泄漏', '化工泵机械密封泄漏隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1311, 14, '化工泵轴承过热', '化工泵轴承过热隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1312, 14, '化工泵气蚀损坏', '化工泵气蚀损坏隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1313, 14, '化工阀门阀杆腐蚀', '化工阀门阀杆腐蚀隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1314, 14, '化工阀门密封面损坏', '化工阀门密封面损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1315, 14, '化工管道静电跨接脱落', '化工管道静电跨接脱落隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1316, 14, '化工管道保温层破损', '化工管道保温层破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1317, 14, '化工塔器填料堵塞', '化工塔器填料堵塞隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1318, 14, '化工塔器塔盘腐蚀', '化工塔器塔盘腐蚀隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1319, 14, '化工换热器管束腐蚀', '化工换热器管束腐蚀隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1320, 14, '化工换热器管板开裂', '化工换热器管板开裂隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1321, 14, '化工压缩机气阀损坏', '化工压缩机气阀损坏隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1322, 14, '化工压缩机活塞环磨损', '化工压缩机活塞环磨损隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1323, 14, '化工压缩机润滑油泄漏', '化工压缩机润滑油泄漏隐患排查', '重大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1324, 14, '化工冷却机组制冷剂泄漏', '化工冷却机组制冷剂泄漏隐患排查', '较大', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1325, 14, '化工分离器液位失控', '化工分离器液位失控隐患排查', '一般', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。'),
(1326, 14, '化工过滤器滤芯堵塞', '化工过滤器滤芯堵塞隐患排查', '重大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.2.1条', '化工企业的建（构）筑物、设备、设施等的防火间距应符合现行国家标准《建筑设计防火规范》GB 50016、《石油化工企业设计防火标准》GB 50160等标准的规定。'),
(1327, 14, '化工干燥机加热管损坏', '化工干燥机加热管损坏隐患排查', '较大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.3.1条', '化工装置的安全设施应符合下列规定：（1）可能发生超压的设备应设置安全阀；（2）可能发生真空的设备应设置真空破坏阀；（3）可能发生火灾的设备应设置灭火设施；（4）可能发生爆炸的设备应设置防爆泄压设施。'),
(1328, 14, '化工输送皮带跑偏', '化工输送皮带跑偏隐患排查', '一般', '《石油化工企业设计防火标准》GB 50160-2008（2018年版）', '第4.2.2条', '石油化工企业的生产区、储存设施区、公用工程设施区、辅助生产设施区、行政办公区等功能分区，应根据火灾危险性、爆炸危险性和环保要求等合理布置。'),
(1329, 14, '化工输送皮带撕裂', '化工输送皮带撕裂隐患排查', '重大', '《石油化工可燃气体和有毒气体检测报警设计标准》GB/T 50493-2019', '第3.0.1条', '石油化工生产装置、储运设施等场所应设置可燃气体和有毒气体检测报警系统，用于检测生产过程中泄漏或积聚的可燃气体或有毒气体，并在气体浓度达到设定值时发出报警信号。'),
(1330, 14, '化工包装机封口不严', '化工包装机封口不严隐患排查', '较大', '《化工建设项目安全设计管理导则》AQ/T 3033-2022', '第8.1条', '化工建设项目应对工艺过程进行危险与可操作性分析，识别工艺过程中的危险与可操作性问题，并提出相应的安全措施。'),
(1331, 14, '化工码垛机抓手故障', '化工码垛机抓手故障隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1332, 14, 'DCS控制系统死机', 'DCS控制系统死机隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1333, 14, 'DCS系统通讯中断', 'DCS系统通讯中断隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1334, 14, 'SIS安全仪表系统故障', 'SIS安全仪表系统故障隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1335, 14, 'GDS气体检测系统失灵', 'GDS气体检测系统失灵隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1336, 14, 'PLC控制器故障', 'PLC控制器故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1337, 14, '紧急停车系统未测试', '紧急停车系统未测试隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1338, 14, '联锁保护装置旁路', '联锁保护装置旁路隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1339, 14, '安全阀整定压力偏差', '安全阀整定压力偏差隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1340, 14, '爆破片超期未更换', '爆破片超期未更换隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1341, 14, '阻火器堵塞', '阻火器堵塞隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1342, 14, '呼吸阀通气不畅', '呼吸阀通气不畅隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1343, 14, '氮封系统压力异常', '氮封系统压力异常隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1344, 14, '火炬系统点火失灵', '火炬系统点火失灵隐患排查', '重大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1345, 14, '火炬长明灯熄灭', '火炬长明灯熄灭隐患排查', '较大', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1346, 14, '废气洗涤塔循环泵故障', '废气洗涤塔循环泵故障隐患排查', '一般', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。'),
(1347, 14, '废气洗涤塔填料堵塞', '废气洗涤塔填料堵塞隐患排查', '重大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.2.1条', '化工企业的建（构）筑物、设备、设施等的防火间距应符合现行国家标准《建筑设计防火规范》GB 50016、《石油化工企业设计防火标准》GB 50160等标准的规定。'),
(1348, 14, '废水处理池曝气故障', '废水处理池曝气故障隐患排查', '较大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.3.1条', '化工装置的安全设施应符合下列规定：（1）可能发生超压的设备应设置安全阀；（2）可能发生真空的设备应设置真空破坏阀；（3）可能发生火灾的设备应设置灭火设施；（4）可能发生爆炸的设备应设置防爆泄压设施。'),
(1349, 14, '废水处理池污泥膨胀', '废水处理池污泥膨胀隐患排查', '一般', '《石油化工企业设计防火标准》GB 50160-2008（2018年版）', '第4.2.2条', '石油化工企业的生产区、储存设施区、公用工程设施区、辅助生产设施区、行政办公区等功能分区，应根据火灾危险性、爆炸危险性和环保要求等合理布置。'),
(1350, 14, '废液焚烧炉燃烧故障', '废液焚烧炉燃烧故障隐患排查', '重大', '《石油化工可燃气体和有毒气体检测报警设计标准》GB/T 50493-2019', '第3.0.1条', '石油化工生产装置、储运设施等场所应设置可燃气体和有毒气体检测报警系统，用于检测生产过程中泄漏或积聚的可燃气体或有毒气体，并在气体浓度达到设定值时发出报警信号。'),
(1351, 14, '废液焚烧炉排烟超标', '废液焚烧炉排烟超标隐患排查', '较大', '《化工建设项目安全设计管理导则》AQ/T 3033-2022', '第8.1条', '化工建设项目应对工艺过程进行危险与可操作性分析，识别工艺过程中的危险与可操作性问题，并提出相应的安全措施。'),
(1352, 14, '固废焚烧炉布袋破损', '固废焚烧炉布袋破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1353, 14, '固废焚烧炉炉排卡涩', '固废焚烧炉炉排卡涩隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1354, 14, 'VOCs治理活性炭饱和', 'VOCs治理活性炭饱和隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1355, 14, 'VOCs治理RTO炉超温', 'VOCs治理RTO炉超温隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1356, 14, 'VOCs治理冷凝器故障', 'VOCs治理冷凝器故障隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1357, 14, '原料仓库温湿度失控', '原料仓库温湿度失控隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1358, 14, '原料仓库通风不良', '原料仓库通风不良隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1359, 14, '原料仓库堆垛超高', '原料仓库堆垛超高隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1360, 14, '原料仓库消防设施不足', '原料仓库消防设施不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1361, 14, '罐区防火堤破损', '罐区防火堤破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1362, 14, '罐区围堰损坏', '罐区围堰损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1363, 14, '罐区消防道路被占用', '罐区消防道路被占用隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1364, 14, '罐区静电消除桩失效', '罐区静电消除桩失效隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1365, 14, '罐区固定喷淋系统故障', '罐区固定喷淋系统故障隐患排查', '重大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1366, 14, '罐区泡沫灭火系统故障', '罐区泡沫灭火系统故障隐患排查', '较大', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1367, 14, '装卸车鹤管泄漏', '装卸车鹤管泄漏隐患排查', '一般', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。'),
(1368, 14, '装卸车静电接地夹失效', '装卸车静电接地夹失效隐患排查', '重大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.2.1条', '化工企业的建（构）筑物、设备、设施等的防火间距应符合现行国家标准《建筑设计防火规范》GB 50016、《石油化工企业设计防火标准》GB 50160等标准的规定。'),
(1369, 14, '装卸车紧急切断阀失效', '装卸车紧急切断阀失效隐患排查', '较大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.3.1条', '化工装置的安全设施应符合下列规定：（1）可能发生超压的设备应设置安全阀；（2）可能发生真空的设备应设置真空破坏阀；（3）可能发生火灾的设备应设置灭火设施；（4）可能发生爆炸的设备应设置防爆泄压设施。'),
(1370, 14, '装卸车防冲撞装置损坏', '装卸车防冲撞装置损坏隐患排查', '一般', '《石油化工企业设计防火标准》GB 50160-2008（2018年版）', '第4.2.2条', '石油化工企业的生产区、储存设施区、公用工程设施区、辅助生产设施区、行政办公区等功能分区，应根据火灾危险性、爆炸危险性和环保要求等合理布置。'),
(1371, 14, '装卸车溢流报警失灵', '装卸车溢流报警失灵隐患排查', '重大', '《石油化工可燃气体和有毒气体检测报警设计标准》GB/T 50493-2019', '第3.0.1条', '石油化工生产装置、储运设施等场所应设置可燃气体和有毒气体检测报警系统，用于检测生产过程中泄漏或积聚的可燃气体或有毒气体，并在气体浓度达到设定值时发出报警信号。'),
(1372, 14, '装卸车油气回收故障', '装卸车油气回收故障隐患排查', '较大', '《化工建设项目安全设计管理导则》AQ/T 3033-2022', '第8.1条', '化工建设项目应对工艺过程进行危险与可操作性分析，识别工艺过程中的危险与可操作性问题，并提出相应的安全措施。'),
(1373, 14, '槽车充装超压', '槽车充装超压隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1374, 14, '槽车充装超速', '槽车充装超速隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1375, 14, '槽车充装液位报警失灵', '槽车充装液位报警失灵隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1376, 14, '化验室通风橱故障', '化验室通风橱故障隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1377, 14, '化验室气瓶未固定', '化验室气瓶未固定隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1378, 14, '化验室试剂混放', '化验室试剂混放隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1379, 14, '化验室废液乱排', '化验室废液乱排隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1380, 14, '化验室电器不防爆', '化验室电器不防爆隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1381, 14, '中控室正压系统故障', '中控室正压系统故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1382, 14, '中控室新风量不足', '中控室新风量不足隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1383, 14, '中控室防静电地板损坏', '中控室防静电地板损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1384, 14, '中控室UPS电源故障', '中控室UPS电源故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1385, 14, '化工安全培训不到位', '化工安全培训不到位隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1386, 14, '化工特殊作业票证不规范', '化工特殊作业票证不规范隐患排查', '重大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1387, 14, '化工动火作业审批不严', '化工动火作业审批不严隐患排查', '较大', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1388, 14, '化工受限空间作业未审批', '化工受限空间作业未审批隐患排查', '一般', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。'),
(1389, 14, '化工高处作业防护不足', '化工高处作业防护不足隐患排查', '重大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.2.1条', '化工企业的建（构）筑物、设备、设施等的防火间距应符合现行国家标准《建筑设计防火规范》GB 50016、《石油化工企业设计防火标准》GB 50160等标准的规定。'),
(1390, 14, '化工吊装作业指挥不规范', '化工吊装作业指挥不规范隐患排查', '较大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.3.1条', '化工装置的安全设施应符合下列规定：（1）可能发生超压的设备应设置安全阀；（2）可能发生真空的设备应设置真空破坏阀；（3）可能发生火灾的设备应设置灭火设施；（4）可能发生爆炸的设备应设置防爆泄压设施。'),
(1391, 14, '化工临时用电未办票证', '化工临时用电未办票证隐患排查', '一般', '《石油化工企业设计防火标准》GB 50160-2008（2018年版）', '第4.2.2条', '石油化工企业的生产区、储存设施区、公用工程设施区、辅助生产设施区、行政办公区等功能分区，应根据火灾危险性、爆炸危险性和环保要求等合理布置。'),
(1392, 14, '化工盲板抽堵作业票证不全', '化工盲板抽堵作业票证不全隐患排查', '重大', '《石油化工可燃气体和有毒气体检测报警设计标准》GB/T 50493-2019', '第3.0.1条', '石油化工生产装置、储运设施等场所应设置可燃气体和有毒气体检测报警系统，用于检测生产过程中泄漏或积聚的可燃气体或有毒气体，并在气体浓度达到设定值时发出报警信号。'),
(1393, 14, '化工断路作业审批不严', '化工断路作业审批不严隐患排查', '较大', '《化工建设项目安全设计管理导则》AQ/T 3033-2022', '第8.1条', '化工建设项目应对工艺过程进行危险与可操作性分析，识别工艺过程中的危险与可操作性问题，并提出相应的安全措施。'),
(1394, 14, '化工动土作业申报不到位', '化工动土作业申报不到位隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1395, 14, '化工装置开停车方案不完善', '化工装置开停车方案不完善隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1396, 14, '化工装置检维修方案不周', '化工装置检维修方案不周隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1397, 14, '化工装置清洗置换不彻底', '化工装置清洗置换不彻底隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1398, 14, '化工装置交出检修条件确认不严', '化工装置交出检修条件确认不严隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1399, 14, '化工装置检修验收不严谨', '化工装置检修验收不严谨隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1400, 14, '化工装置开车前安全检查不到位', '化工装置开车前安全检查不到位隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1401, 14, '化工工艺变更管理不规范', '化工工艺变更管理不规范隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1402, 14, '化工设备变更管理不规范', '化工设备变更管理不规范隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1403, 14, '化工人员变更管理不规范', '化工人员变更管理不规范隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1404, 14, '化工操作规程未及时修订', '化工操作规程未及时修订隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1405, 14, '化工岗位操作法不完善', '化工岗位操作法不完善隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1406, 14, '化工工艺指标偏离未及时纠正', '化工工艺指标偏离未及时纠正隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1407, 14, '化工联锁摘除未审批', '化工联锁摘除未审批隐患排查', '重大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1408, 14, '化工联锁投用未确认', '化工联锁投用未确认隐患排查', '较大', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1409, 14, '化工紧急停车按钮未定期测试', '化工紧急停车按钮未定期测试隐患排查', '一般', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。'),
(1410, 14, '化工可燃有毒气体报警处置不及时', '化工可燃有毒气体报警处置不及时隐患排查', '重大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.2.1条', '化工企业的建（构）筑物、设备、设施等的防火间距应符合现行国家标准《建筑设计防火规范》GB 50016、《石油化工企业设计防火标准》GB 50160等标准的规定。'),
(1411, 14, '化工报警值设定不合理', '化工报警值设定不合理隐患排查', '较大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.3.1条', '化工装置的安全设施应符合下列规定：（1）可能发生超压的设备应设置安全阀；（2）可能发生真空的设备应设置真空破坏阀；（3）可能发生火灾的设备应设置灭火设施；（4）可能发生爆炸的设备应设置防爆泄压设施。'),
(1412, 14, '化工报警台账记录不完整', '化工报警台账记录不完整隐患排查', '一般', '《石油化工企业设计防火标准》GB 50160-2008（2018年版）', '第4.2.2条', '石油化工企业的生产区、储存设施区、公用工程设施区、辅助生产设施区、行政办公区等功能分区，应根据火灾危险性、爆炸危险性和环保要求等合理布置。'),
(1413, 14, '化工报警统计分析不到位', '化工报警统计分析不到位隐患排查', '重大', '《石油化工可燃气体和有毒气体检测报警设计标准》GB/T 50493-2019', '第3.0.1条', '石油化工生产装置、储运设施等场所应设置可燃气体和有毒气体检测报警系统，用于检测生产过程中泄漏或积聚的可燃气体或有毒气体，并在气体浓度达到设定值时发出报警信号。'),
(1414, 14, '化工HAZOP分析未定期开展', '化工HAZOP分析未定期开展隐患排查', '较大', '《化工建设项目安全设计管理导则》AQ/T 3033-2022', '第8.1条', '化工建设项目应对工艺过程进行危险与可操作性分析，识别工艺过程中的危险与可操作性问题，并提出相应的安全措施。'),
(1415, 14, '化工SIL评估未定期开展', '化工SIL评估未定期开展隐患排查', '一般', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1416, 14, '化工安全仪表功能测试不到位', '化工安全仪表功能测试不到位隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1417, 14, '化工安全阀在线校验不规范', '化工安全阀在线校验不规范隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1418, 14, '化工防爆电气设备选型不当', '化工防爆电气设备选型不当隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1419, 14, '化工防爆电气线路敷设不规范', '化工防爆电气线路敷设不规范隐患排查', '重大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1420, 14, '化工防静电接地系统不完善', '化工防静电接地系统不完善隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1421, 14, '化工防静电地面破损', '化工防静电地面破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1422, 14, '化工防雷防静电检测过期', '化工防雷防静电检测过期隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1423, 14, '化工防雷引下线断裂', '化工防雷引下线断裂隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1424, 14, '化工接地网电阻超标', '化工接地网电阻超标隐患排查', '一般', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1425, 14, '化工接地线断裂', '化工接地线断裂隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1426, 14, '化工地下管网腐蚀泄漏', '化工地下管网腐蚀泄漏隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1427, 14, '化工公用工程中断应急预案缺失', '化工公用工程中断应急预案缺失隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1428, 14, '化工氮气系统误操作伤人', '化工氮气系统误操作伤人隐患排查', '重大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1429, 14, '化工蒸汽系统烫伤风险', '化工蒸汽系统烫伤风险隐患排查', '较大', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1430, 14, '化工压缩空气系统含水', '化工压缩空气系统含水隐患排查', '一般', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。'),
(1431, 14, '化工循环水系统结垢', '化工循环水系统结垢隐患排查', '重大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.2.1条', '化工企业的建（构）筑物、设备、设施等的防火间距应符合现行国家标准《建筑设计防火规范》GB 50016、《石油化工企业设计防火标准》GB 50160等标准的规定。'),
(1432, 14, '化工消防水系统无水', '化工消防水系统无水隐患排查', '较大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.3.1条', '化工装置的安全设施应符合下列规定：（1）可能发生超压的设备应设置安全阀；（2）可能发生真空的设备应设置真空破坏阀；（3）可能发生火灾的设备应设置灭火设施；（4）可能发生爆炸的设备应设置防爆泄压设施。'),
(1433, 14, '化工消防水系统水压不足', '化工消防水系统水压不足隐患排查', '一般', '《石油化工企业设计防火标准》GB 50160-2008（2018年版）', '第4.2.2条', '石油化工企业的生产区、储存设施区、公用工程设施区、辅助生产设施区、行政办公区等功能分区，应根据火灾危险性、爆炸危险性和环保要求等合理布置。'),
(1434, 14, '化工消防水系统阀门误关闭', '化工消防水系统阀门误关闭隐患排查', '重大', '《石油化工可燃气体和有毒气体检测报警设计标准》GB/T 50493-2019', '第3.0.1条', '石油化工生产装置、储运设施等场所应设置可燃气体和有毒气体检测报警系统，用于检测生产过程中泄漏或积聚的可燃气体或有毒气体，并在气体浓度达到设定值时发出报警信号。'),
(1435, 15, '顶板离层监测报警', '顶板离层监测报警隐患排查', '较大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1436, 15, '工作面片帮', '工作面片帮隐患排查', '一般', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1437, 15, '采掘工作面冒顶', '采掘工作面冒顶隐患排查', '重大', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。'),
(1438, 15, '采煤工作面透水', '采煤工作面透水隐患排查', '较大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.2.1条', '化工企业的建（构）筑物、设备、设施等的防火间距应符合现行国家标准《建筑设计防火规范》GB 50016、《石油化工企业设计防火标准》GB 50160等标准的规定。'),
(1439, 15, '采掘工作面瓦斯超限', '采掘工作面瓦斯超限隐患排查', '一般', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.3.1条', '化工装置的安全设施应符合下列规定：（1）可能发生超压的设备应设置安全阀；（2）可能发生真空的设备应设置真空破坏阀；（3）可能发生火灾的设备应设置灭火设施；（4）可能发生爆炸的设备应设置防爆泄压设施。'),
(1440, 15, '采掘工作面煤尘堆积', '采掘工作面煤尘堆积隐患排查', '重大', '《石油化工企业设计防火标准》GB 50160-2008（2018年版）', '第4.2.2条', '石油化工企业的生产区、储存设施区、公用工程设施区、辅助生产设施区、行政办公区等功能分区，应根据火灾危险性、爆炸危险性和环保要求等合理布置。'),
(1441, 15, '采掘工作面通风不良', '采掘工作面通风不良隐患排查', '较大', '《石油化工可燃气体和有毒气体检测报警设计标准》GB/T 50493-2019', '第3.0.1条', '石油化工生产装置、储运设施等场所应设置可燃气体和有毒气体检测报警系统，用于检测生产过程中泄漏或积聚的可燃气体或有毒气体，并在气体浓度达到设定值时发出报警信号。'),
(1442, 15, '采掘工作面空顶作业', '采掘工作面空顶作业隐患排查', '一般', '《化工建设项目安全设计管理导则》AQ/T 3033-2022', '第8.1条', '化工建设项目应对工艺过程进行危险与可操作性分析，识别工艺过程中的危险与可操作性问题，并提出相应的安全措施。'),
(1443, 15, '采掘工作面炮眼堵塞', '采掘工作面炮眼堵塞隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1444, 15, '采掘工作面拒爆', '采掘工作面拒爆隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1445, 15, '采掘工作面残爆', '采掘工作面残爆隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1446, 15, '采掘工作面杂散电流超标', '采掘工作面杂散电流超标隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1447, 15, '采掘工作面局部通风机循环风', '采掘工作面局部通风机循环风隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1448, 15, '采掘工作面风筒破损', '采掘工作面风筒破损隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1449, 15, '采掘工作面风筒脱节', '采掘工作面风筒脱节隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1450, 15, '采掘工作面风筒距工作面过远', '采掘工作面风筒距工作面过远隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1451, 15, '矿井主通风机故障', '矿井主通风机故障隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1452, 15, '矿井主通风机轴承超温', '矿井主通风机轴承超温隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1453, 15, '矿井局部通风机无风电闭锁', '矿井局部通风机无风电闭锁隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1454, 15, '矿井局部通风机无瓦斯电闭锁', '矿井局部通风机无瓦斯电闭锁隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1455, 15, '矿井通风设施损坏', '矿井通风设施损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1456, 15, '矿井风门损坏', '矿井风门损坏隐患排查', '较大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1457, 15, '矿井风桥损坏', '矿井风桥损坏隐患排查', '一般', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1458, 15, '矿井密闭墙开裂', '矿井密闭墙开裂隐患排查', '重大', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。'),
(1459, 15, '矿井防爆门失效', '矿井防爆门失效隐患排查', '较大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.2.1条', '化工企业的建（构）筑物、设备、设施等的防火间距应符合现行国家标准《建筑设计防火规范》GB 50016、《石油化工企业设计防火标准》GB 50160等标准的规定。'),
(1460, 15, '矿井瓦斯抽采泵故障', '矿井瓦斯抽采泵故障隐患排查', '一般', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.3.1条', '化工装置的安全设施应符合下列规定：（1）可能发生超压的设备应设置安全阀；（2）可能发生真空的设备应设置真空破坏阀；（3）可能发生火灾的设备应设置灭火设施；（4）可能发生爆炸的设备应设置防爆泄压设施。'),
(1461, 15, '矿井瓦斯抽采管路破损', '矿井瓦斯抽采管路破损隐患排查', '重大', '《石油化工企业设计防火标准》GB 50160-2008（2018年版）', '第4.2.2条', '石油化工企业的生产区、储存设施区、公用工程设施区、辅助生产设施区、行政办公区等功能分区，应根据火灾危险性、爆炸危险性和环保要求等合理布置。'),
(1462, 15, '矿井瓦斯抽采钻孔塌孔', '矿井瓦斯抽采钻孔塌孔隐患排查', '较大', '《石油化工可燃气体和有毒气体检测报警设计标准》GB/T 50493-2019', '第3.0.1条', '石油化工生产装置、储运设施等场所应设置可燃气体和有毒气体检测报警系统，用于检测生产过程中泄漏或积聚的可燃气体或有毒气体，并在气体浓度达到设定值时发出报警信号。'),
(1463, 15, '矿井瓦斯抽采浓度异常', '矿井瓦斯抽采浓度异常隐患排查', '一般', '《化工建设项目安全设计管理导则》AQ/T 3033-2022', '第8.1条', '化工建设项目应对工艺过程进行危险与可操作性分析，识别工艺过程中的危险与可操作性问题，并提出相应的安全措施。'),
(1464, 15, '矿井瓦斯抽采流量偏低', '矿井瓦斯抽采流量偏低隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1465, 15, '矿井瓦斯突出预测指标超标', '矿井瓦斯突出预测指标超标隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1466, 15, '矿井瓦斯突出逃生通道不畅', '矿井瓦斯突出逃生通道不畅隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1467, 15, '矿井瓦斯检测仪失效', '矿井瓦斯检测仪失效隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1468, 15, '矿井瓦斯传感器超期', '矿井瓦斯传感器超期隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1469, 15, '矿井瓦斯传感器安装位置不当', '矿井瓦斯传感器安装位置不当隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1470, 15, '矿井瓦斯断电仪故障', '矿井瓦斯断电仪故障隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1471, 15, '矿井瓦斯巡检空班漏检', '矿井瓦斯巡检空班漏检隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1472, 15, '矿井瓦斯日报表造假', '矿井瓦斯日报表造假隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1473, 15, '矿井煤尘爆炸性鉴定缺失', '矿井煤尘爆炸性鉴定缺失隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1474, 15, '矿井隔爆水袋水量不足', '矿井隔爆水袋水量不足隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1475, 15, '矿井隔爆水袋安装不规范', '矿井隔爆水袋安装不规范隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1476, 15, '矿井煤尘清扫制度不落实', '矿井煤尘清扫制度不落实隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1477, 15, '矿井煤尘浓度超限', '矿井煤尘浓度超限隐患排查', '较大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1478, 15, '矿井煤尘监测仪器失效', '矿井煤尘监测仪器失效隐患排查', '一般', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1479, 15, '矿井防尘供水管路损坏', '矿井防尘供水管路损坏隐患排查', '重大', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。'),
(1480, 15, '矿井防尘喷雾装置堵塞', '矿井防尘喷雾装置堵塞隐患排查', '较大', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.2.1条', '化工企业的建（构）筑物、设备、设施等的防火间距应符合现行国家标准《建筑设计防火规范》GB 50016、《石油化工企业设计防火标准》GB 50160等标准的规定。'),
(1481, 15, '矿井煤层注水设施损坏', '矿井煤层注水设施损坏隐患排查', '一般', '《化工企业安全卫生设计规范》HG 20571-2014', '第4.3.1条', '化工装置的安全设施应符合下列规定：（1）可能发生超压的设备应设置安全阀；（2）可能发生真空的设备应设置真空破坏阀；（3）可能发生火灾的设备应设置灭火设施；（4）可能发生爆炸的设备应设置防爆泄压设施。'),
(1482, 15, '矿井自然发火监测系统故障', '矿井自然发火监测系统故障隐患排查', '重大', '《石油化工企业设计防火标准》GB 50160-2008（2018年版）', '第4.2.2条', '石油化工企业的生产区、储存设施区、公用工程设施区、辅助生产设施区、行政办公区等功能分区，应根据火灾危险性、爆炸危险性和环保要求等合理布置。'),
(1483, 15, '矿井束管监测系统管路破损', '矿井束管监测系统管路破损隐患排查', '较大', '《石油化工可燃气体和有毒气体检测报警设计标准》GB/T 50493-2019', '第3.0.1条', '石油化工生产装置、储运设施等场所应设置可燃气体和有毒气体检测报警系统，用于检测生产过程中泄漏或积聚的可燃气体或有毒气体，并在气体浓度达到设定值时发出报警信号。'),
(1484, 15, '矿井注浆系统管路堵塞', '矿井注浆系统管路堵塞隐患排查', '一般', '《化工建设项目安全设计管理导则》AQ/T 3033-2022', '第8.1条', '化工建设项目应对工艺过程进行危险与可操作性分析，识别工艺过程中的危险与可操作性问题，并提出相应的安全措施。'),
(1485, 15, '矿井注氮系统压力不足', '矿井注氮系统压力不足隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1486, 15, '矿井注氮系统泄漏', '矿井注氮系统泄漏隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1487, 15, '矿井均压灭火设施失效', '矿井均压灭火设施失效隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1488, 15, '矿井阻化剂喷洒设施损坏', '矿井阻化剂喷洒设施损坏隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1489, 15, '矿井防火门失效', '矿井防火门失效隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1490, 15, '矿井火区封闭不严', '矿井火区封闭不严隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1491, 15, '矿井防灭火器材配备不足', '矿井防灭火器材配备不足隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1492, 15, '矿井防灭火器材超期', '矿井防灭火器材超期隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1493, 15, '矿井主要排水泵故障', '矿井主要排水泵故障隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1494, 15, '矿井排水泵效率下降', '矿井排水泵效率下降隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1495, 15, '矿井排水管路破损', '矿井排水管路破损隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1496, 15, '矿井排水管路结垢', '矿井排水管路结垢隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1497, 15, '矿井水仓淤积', '矿井水仓淤积隐患排查', '重大', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1498, 15, '矿井水仓容量不足', '矿井水仓容量不足隐患排查', '较大', '《危险化学品安全管理条例》', '第十五条', '危险化学品生产企业应当提供与其生产的危险化学品相符的化学品安全技术说明书，并在危险化学品包装（包括外包装件）上粘贴或者拴挂与包装内危险化学品相符的化学品安全标签。化学品安全技术说明书和化学品安全标签所载明的内容应当符合国家标准的要求。'),
(1499, 15, '矿井防水闸门失效', '矿井防水闸门失效隐患排查', '一般', '《危险化学品安全管理条例》', '第二十条', '生产、储存危险化学品的单位，应当根据其生产、储存的危险化学品的种类和危险特性，在作业场所设置相应的监测、监控、通风、防晒、调温、防火、灭火、防爆、泄压、防毒、中和、防潮、防雷、防静电、防腐、防泄漏以及防护围堤或者隔离操作等安全设施、设备，并按照国家标准、行业标准或者国家有关规定对安全设施、设备进行经常性维护、保养，保证安全设施、设备的正常使用。'),
(1500, 15, '矿井排水沟清理不及时', '矿井排水沟清理不及时隐患排查', '重大', '《危险化学品安全管理条例》', '第七十条', '危险化学品单位应当制定本单位危险化学品事故应急预案，配备应急救援人员和必要的应急救援器材、设备，并定期组织应急救援演练。')